def write(rel, text):
    p = PKG / rel
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(text, encoding="utf-8")

SDK_CONFIG = '# -*- coding: utf-8 -*-\nfrom pathlib import Path\n\nBASE_DIR = Path(r"C:\\Users\\MSI\\Desktop\\kik_proje")\nSTATE_DIR = BASE_DIR / "production_state"\nREPORT_DIR = BASE_DIR / "raporlar"\n\nMETRICS_DIR = STATE_DIR / "metrics"\nINTELLIGENCE_DIR = METRICS_DIR / "intelligence"\nINTELLIGENCE_SDK_DIR = INTELLIGENCE_DIR / "sdk"\n\nMETRICS_SNAPSHOT = METRICS_DIR / "204_metrics_snapshot.json"\nMETRICS_HISTORY = METRICS_DIR / "204_metrics_history.jsonl"\nDASHBOARD_METRICS = METRICS_DIR / "204_dashboard_metrics.json"\nTREND_FILE = METRICS_DIR / "trends" / "205_metrics_trends.json"\n\nSDK_STATUS_FILE = INTELLIGENCE_SDK_DIR / "205_0_sdk_status.json"\nSDK_TEST_OUTPUT = INTELLIGENCE_SDK_DIR / "205_0_sdk_test_output.json"\n\nTARGET_DB_COUNT = 100000\n\nRISK_LEVELS = ["LOW", "MEDIUM", "HIGH"]\nHEALTH_LEVELS = ["LOW", "MEDIUM", "HIGH"]\n'

SDK_UTILS = '# -*- coding: utf-8 -*-\nimport json\nimport shutil\nfrom pathlib import Path\nfrom datetime import datetime\n\ndef now_stamp():\n    return datetime.now().strftime("%Y%m%d_%H%M%S")\n\ndef now_text():\n    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")\n\ndef ensure_dirs(*dirs):\n    for d in dirs:\n        Path(d).mkdir(parents=True, exist_ok=True)\n\ndef safe_read(path, limit_chars=5000000):\n    path = Path(path)\n    if not path.exists():\n        return ""\n    for enc in ("utf-8", "utf-8-sig", "cp1254", "latin-1"):\n        try:\n            return path.read_text(encoding=enc, errors="ignore")[:limit_chars]\n        except Exception:\n            pass\n    return ""\n\ndef safe_json(path):\n    path = Path(path)\n    if not path.exists():\n        return None\n    try:\n        return json.loads(safe_read(path))\n    except Exception:\n        return None\n\ndef read_jsonl(path):\n    path = Path(path)\n    rows = []\n    invalid = 0\n    if not path.exists():\n        return rows, invalid\n    for line in safe_read(path).splitlines():\n        if not line.strip():\n            continue\n        try:\n            rows.append(json.loads(line))\n        except Exception:\n            invalid += 1\n    return rows, invalid\n\ndef write_json(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")\n\ndef append_jsonl(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    with path.open("a", encoding="utf-8") as f:\n        f.write(json.dumps(data, ensure_ascii=False) + "\\n")\n\ndef disk_free_gb(path):\n    usage = shutil.disk_usage(str(path))\n    return round(usage.free / (1024 ** 3), 2)\n\ndef clamp(value, min_value=0, max_value=100):\n    try:\n        value = float(value)\n    except Exception:\n        value = 0\n    return max(min_value, min(max_value, value))\n'

LOADER = '# -*- coding: utf-8 -*-\nfrom .config import METRICS_SNAPSHOT, METRICS_HISTORY, DASHBOARD_METRICS, TREND_FILE\nfrom .utils import safe_json, read_jsonl\n\nclass IntelligenceDataLoader:\n    def load_snapshot(self):\n        return safe_json(METRICS_SNAPSHOT)\n\n    def load_history(self):\n        rows, invalid = read_jsonl(METRICS_HISTORY)\n        return {"rows": rows, "invalid": invalid}\n\n    def load_dashboard(self):\n        return safe_json(DASHBOARD_METRICS)\n\n    def load_trends(self):\n        return safe_json(TREND_FILE)\n\n    def load_all(self):\n        return {\n            "snapshot": self.load_snapshot(),\n            "history": self.load_history(),\n            "dashboard": self.load_dashboard(),\n            "trends": self.load_trends(),\n        }\n'

NORMALIZER = '# -*- coding: utf-8 -*-\ndef get_nested(d, path, default=None):\n    cur = d\n    for key in path:\n        if not isinstance(cur, dict):\n            return default\n        cur = cur.get(key)\n        if cur is None:\n            return default\n    return cur\n\nclass IntelligenceNormalizer:\n    def normalize(self, data):\n        snapshot = data.get("snapshot") or {}\n        dashboard = data.get("dashboard") or {}\n        trends = data.get("trends") or {}\n\n        metrics = snapshot.get("metrics", {})\n        result = snapshot.get("result", {})\n\n        normalized = {\n            "health": {\n                "score": result.get("score"),\n                "decision": result.get("decision"),\n                "errors": len(result.get("errors", [])),\n                "warnings": len(result.get("warnings", [])),\n            },\n            "system": {\n                "db_count": get_nested(metrics, ["db", "count"], get_nested(dashboard, ["system", "db_count"], 0)),\n                "disk_free_gb": get_nested(metrics, ["disk", "free_gb"], get_nested(dashboard, ["system", "disk_free_gb"], None)),\n            },\n            "queue": {\n                "total": get_nested(metrics, ["queue", "total"], get_nested(dashboard, ["queue", "total"], 0)),\n                "waiting": get_nested(metrics, ["queue", "waiting"], get_nested(dashboard, ["queue", "waiting"], 0)),\n                "running": get_nested(metrics, ["queue", "running"], get_nested(dashboard, ["queue", "running"], 0)),\n                "finished": get_nested(metrics, ["queue", "finished"], get_nested(dashboard, ["queue", "finished"], 0)),\n                "failed": get_nested(metrics, ["queue", "failed"], get_nested(dashboard, ["queue", "failed"], 0)),\n                "completion_rate": get_nested(metrics, ["queue", "completion_rate"], get_nested(dashboard, ["queue", "completion_rate"], 0)),\n            },\n            "workers": {\n                "total": get_nested(metrics, ["workers", "total"], get_nested(dashboard, ["workers", "total"], 0)),\n                "idle": get_nested(metrics, ["workers", "idle"], get_nested(dashboard, ["workers", "idle"], 0)),\n                "running": get_nested(metrics, ["workers", "running"], get_nested(dashboard, ["workers", "running"], 0)),\n                "jobs_completed": get_nested(metrics, ["workers", "jobs_completed"], get_nested(dashboard, ["workers", "jobs_completed"], 0)),\n                "jobs_failed": get_nested(metrics, ["workers", "jobs_failed"], get_nested(dashboard, ["workers", "jobs_failed"], 0)),\n            },\n            "events": {\n                "total": get_nested(metrics, ["events", "total"], get_nested(dashboard, ["events", "total"], 0)),\n                "invalid": get_nested(metrics, ["events", "invalid"], get_nested(dashboard, ["events", "invalid"], 0)),\n                "by_severity": get_nested(metrics, ["events", "by_severity"], get_nested(dashboard, ["events", "by_severity"], {})),\n            },\n            "logs": {\n                "total": get_nested(metrics, ["logs", "total"], get_nested(dashboard, ["logs", "total"], 0)),\n                "invalid": get_nested(metrics, ["logs", "invalid"], get_nested(dashboard, ["logs", "invalid"], 0)),\n                "by_level": get_nested(metrics, ["logs", "by_severity"], get_nested(dashboard, ["logs", "by_level"], {})),\n            },\n            "trends": {\n                "db_delta": get_nested(trends, ["trends", "growth", "db_delta"], 0),\n                "event_delta": get_nested(trends, ["trends", "growth", "event_delta"], 0),\n                "log_delta": get_nested(trends, ["trends", "growth", "log_delta"], 0),\n                "queue_finished_delta": get_nested(trends, ["trends", "growth", "queue_finished_delta"], 0),\n            }\n        }\n        return normalized\n'

SCORING = '# -*- coding: utf-8 -*-\nfrom .utils import clamp\n\nclass IntelligenceScoring:\n    def score_queue(self, queue):\n        score = 100\n        if queue.get("failed", 0):\n            score -= min(30, queue.get("failed", 0) * 10)\n        if queue.get("running", 0) > 0:\n            score -= 0\n        if queue.get("completion_rate", 0) < 50 and queue.get("total", 0) > 0:\n            score -= 10\n        return int(clamp(score))\n\n    def score_workers(self, workers):\n        score = 100\n        if workers.get("total", 0) == 0:\n            return 0\n        if workers.get("jobs_failed", 0):\n            score -= min(30, workers.get("jobs_failed", 0) * 10)\n        return int(clamp(score))\n\n    def score_events(self, events):\n        score = 100\n        if events.get("invalid", 0):\n            score -= min(30, events.get("invalid", 0) * 10)\n        sev = events.get("by_severity") or {}\n        score -= min(40, (sev.get("ERROR", 0) + sev.get("CRITICAL", 0)) * 10)\n        score -= min(10, sev.get("WARNING", 0) * 2)\n        return int(clamp(score))\n\n    def score_logs(self, logs):\n        score = 100\n        if logs.get("invalid", 0):\n            score -= min(30, logs.get("invalid", 0) * 10)\n        levels = logs.get("by_level") or {}\n        score -= min(40, (levels.get("ERROR", 0) + levels.get("CRITICAL", 0)) * 10)\n        score -= min(10, levels.get("WARNING", 0) * 2)\n        return int(clamp(score))\n\n    def global_score(self, normalized):\n        parts = [\n            normalized.get("health", {}).get("score") or 0,\n            self.score_queue(normalized.get("queue", {})),\n            self.score_workers(normalized.get("workers", {})),\n            self.score_events(normalized.get("events", {})),\n            self.score_logs(normalized.get("logs", {})),\n        ]\n        return round(sum(parts) / len(parts), 2) if parts else 0\n'

RISK = '# -*- coding: utf-8 -*-\nclass IntelligenceRisk:\n    def level(self, score):\n        if score >= 90:\n            return "LOW"\n        if score >= 70:\n            return "MEDIUM"\n        return "HIGH"\n\n    def reasons(self, normalized):\n        reasons = []\n        if normalized.get("queue", {}).get("failed", 0):\n            reasons.append("Queue içinde failed job var.")\n        if normalized.get("events", {}).get("invalid", 0):\n            reasons.append("Event log içinde invalid satır var.")\n        if normalized.get("logs", {}).get("invalid", 0):\n            reasons.append("Logger içinde invalid satır var.")\n        if (normalized.get("health", {}).get("errors") or 0) > 0:\n            reasons.append("Metrics health errors mevcut.")\n        return reasons\n'

RECOMMENDATION = '# -*- coding: utf-8 -*-\nclass IntelligenceRecommendation:\n    def recommend(self, normalized, score, risk_level):\n        queue = normalized.get("queue", {})\n        workers = normalized.get("workers", {})\n        db_count = normalized.get("system", {}).get("db_count", 0)\n\n        if risk_level == "HIGH":\n            return "Yeni production batch başlatmadan önce hata kaynakları incelenmelidir."\n\n        if queue.get("failed", 0):\n            return "Failed job bulundu; önce queue recovery veya retry planı çalıştırılmalıdır."\n\n        if workers.get("idle", 0) == workers.get("total", 0) and workers.get("total", 0) > 0:\n            return "Worker\'lar boşta görünüyor; kontrollü yeni batch başlatılabilir."\n\n        if db_count and db_count < 100000:\n            return "Production platform sağlıklı; 100.000 karar hedefine yönelik kontrollü üretim sürdürülebilir."\n\n        return "Sistem normal görünmektedir; mevcut plan korunabilir."\n'

SUMMARY = '# -*- coding: utf-8 -*-\nclass IntelligenceSummary:\n    def build(self, normalized, score, risk_level, recommendation):\n        db_count = normalized.get("system", {}).get("db_count")\n        queue = normalized.get("queue", {})\n        workers = normalized.get("workers", {})\n        events = normalized.get("events", {})\n        logs = normalized.get("logs", {})\n\n        return (\n            f"NeoLegal Intelligence değerlendirmesine göre platform stabilite skoru {score}/100 seviyesindedir. "\n            f"Risk seviyesi {risk_level} olarak hesaplanmıştır. "\n            f"Veritabanında {db_count} kart bulunmaktadır. "\n            f"Queue toplam {queue.get(\'total\')} iş, {queue.get(\'finished\')} tamamlanan iş ve {queue.get(\'failed\')} failed iş içermektedir. "\n            f"{workers.get(\'total\')} worker tanımlıdır; {workers.get(\'idle\')} worker idle durumdadır. "\n            f"Event Bus toplam {events.get(\'total\')} olay, Logger toplam {logs.get(\'total\')} log kaydı içermektedir. "\n            f"Öneri: {recommendation}"\n        )\n'

EXPORTER = '# -*- coding: utf-8 -*-\nfrom .utils import write_json, now_stamp, now_text\nfrom .config import STATE_DIR, REPORT_DIR, INTELLIGENCE_SDK_DIR, SDK_TEST_OUTPUT\n\nclass IntelligenceExporter:\n    def export(self, payload, name_prefix="205_0_sdk"):\n        ts = now_stamp()\n        state = STATE_DIR / f"{name_prefix}_state_{ts}.json"\n        report = REPORT_DIR / f"{name_prefix}_raporu_{ts}.txt"\n        output = INTELLIGENCE_SDK_DIR / f"{name_prefix}_output.json"\n\n        write_json(output, payload)\n        write_json(state, payload)\n\n        result = payload.get("result", {})\n        lines = [\n            "="*80,\n            "205.0 INTELLIGENCE SDK",\n            "="*80,\n            f"Time      : {now_text()}",\n            f"Score     : {result.get(\'score\')}",\n            f"Risk      : {result.get(\'risk_level\')}",\n            f"Decision  : {result.get(\'decision\')}",\n            "",\n            "SUMMARY",\n            "-"*80,\n            result.get("executive_summary", ""),\n            "",\n            "RECOMMENDATION",\n            "-"*80,\n            result.get("recommendation", ""),\n            "",\n            "Dosyalar:",\n            str(output),\n            str(state),\n            str(report),\n        ]\n        report.write_text("\\n".join(lines), encoding="utf-8")\n        return {"output": str(output), "state": str(state), "report": str(report)}\n'

ENGINE = '# -*- coding: utf-8 -*-\nfrom .config import BASE_DIR, STATE_DIR, REPORT_DIR, INTELLIGENCE_SDK_DIR\nfrom .utils import ensure_dirs, now_text, disk_free_gb\nfrom .loader import IntelligenceDataLoader\nfrom .normalizer import IntelligenceNormalizer\nfrom .scoring import IntelligenceScoring\nfrom .risk import IntelligenceRisk\nfrom .recommendation import IntelligenceRecommendation\nfrom .summary import IntelligenceSummary\nfrom .exporter import IntelligenceExporter\n\nclass IntelligenceEngine:\n    def __init__(self, engine_name="Generic Intelligence Engine"):\n        ensure_dirs(STATE_DIR, REPORT_DIR, INTELLIGENCE_SDK_DIR)\n        self.engine_name = engine_name\n        self.loader = IntelligenceDataLoader()\n        self.normalizer = IntelligenceNormalizer()\n        self.scoring = IntelligenceScoring()\n        self.risk = IntelligenceRisk()\n        self.recommendation = IntelligenceRecommendation()\n        self.summary = IntelligenceSummary()\n        self.exporter = IntelligenceExporter()\n\n    def run(self):\n        raw = self.loader.load_all()\n        normalized = self.normalizer.normalize(raw)\n        score = self.scoring.global_score(normalized)\n        risk_level = self.risk.level(score)\n        reasons = self.risk.reasons(normalized)\n        recommendation = self.recommendation.recommend(normalized, score, risk_level)\n        executive_summary = self.summary.build(normalized, score, risk_level, recommendation)\n\n        decision = "INTELLIGENCE SDK READY" if score >= 90 else ("INTELLIGENCE SDK REVIEW" if score >= 70 else "INTELLIGENCE SDK RISK")\n\n        payload = {\n            "module": "205.0 Intelligence SDK",\n            "engine_name": self.engine_name,\n            "created_at": now_text(),\n            "disk_free_gb": disk_free_gb(BASE_DIR),\n            "normalized": normalized,\n            "result": {\n                "score": score,\n                "risk_level": risk_level,\n                "risk_reasons": reasons,\n                "decision": decision,\n                "recommendation": recommendation,\n                "executive_summary": executive_summary,\n            }\n        }\n\n        paths = self.exporter.export(payload, name_prefix="205_0_intelligence_sdk")\n        return {"payload": payload, "paths": paths}\n'

MANAGER = '# -*- coding: utf-8 -*-\nimport argparse\nfrom core.engine import IntelligenceEngine\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--test", action="store_true")\n    parser.add_argument("--status", action="store_true")\n    args = parser.parse_args()\n\n    engine = IntelligenceEngine(engine_name="SDK Self Test")\n    res = engine.run()\n    result = res["payload"]["result"]\n\n    print("="*80)\n    print("205.0 INTELLIGENCE SDK TAMAMLANDI")\n    print("="*80)\n    print(f"Score          : {result[\'score\']} / 100")\n    print(f"Decision       : {result[\'decision\']}")\n    print(f"Risk Level     : {result[\'risk_level\']}")\n    print(f"Risk Reasons   : {len(result[\'risk_reasons\'])}")\n    print("")\n    print("Recommendation:")\n    print(result["recommendation"])\n    print("")\n    print("Dosyalar:")\n    print(res["paths"]["output"])\n    print(res["paths"]["report"])\n\nif __name__ == "__main__":\n    main()\n'

BRIDGE = '# -*- coding: utf-8 -*-\nimport sys\nfrom pathlib import Path\nPACKAGE_DIR = Path(__file__).resolve().parent / "205"\nsys.path.insert(0, str(PACKAGE_DIR))\nfrom sdk_manager import main\nif __name__ == "__main__":\n    main()\n'

README = '# 205.0 Intelligence SDK\n\n205.x intelligence motorları için ortak SDK katmanıdır.\n\nBileşenler:\n- core/loader.py\n- core/normalizer.py\n- core/scoring.py\n- core/risk.py\n- core/recommendation.py\n- core/summary.py\n- core/exporter.py\n- core/engine.py\n\nKomut:\npython ".py\\205_Intelligence_SDK.py" --test\n'

