    (PY / "205_Intelligence_SDK.py").write_text(BRIDGE, encoding="utf-8")

    print("="*80)
    print("205.0 INTELLIGENCE SDK INSTALLER TAMAMLANDI")
    print("="*80)
    print("Kurulan SDK:")
    print(CORE)
    print("")
    print("Şimdi çalıştır:")
    print(r'cd /d C:\Users\MSI\Desktop\kik_proje')
    print(r'python ".py\205_Intelligence_SDK.py" --test')

